#include <vector>
#include <algorithm>
using namespace std;

class FenwickTree {
    vector<long long> tree;
    int size;
public:
    FenwickTree(int size) : size(size) {
        tree.resize(size + 2, 0);
    }
    void update(int index, long long delta) {
        index += 1; // 1-based index
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        index += 1;
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<FenwickTree> bits(6); // for k=0 to 5
    for (int i = 0; i < 6; ++i) {
        bits[i] = FenwickTree(n);
    }
    // Precompute the depths for each number
    vector<long long> depths(n);
    for (int i = 0; i < n; ++i) {
        long long x = nums[i];
        long long d = 0;
        while (x != 1) {
            x = __builtin_popcountll(x);
            d++;
        }
        depths[i] = d;
        if (d <= 5) {
            bits[d].update(i, 1);
        }
    }
    // Process queries
    vector<long long> answer;
    for (auto& q : queries) {
        if (q[0] == 1) {
            int l = q[1], r = q[2], k = q[3];
            if (k < 0 || k > 5) {
                answer.push_back(0);
                continue;
            }
            long long res = bits[k].range_query(l, r);
            answer.push_back(res);
        } else {
            int idx = q[1], val = q[2];
            long long old_val = nums[idx];
            long long old_depth = depths[idx];
            if (old_depth <= 5) {
                bits[old_depth].update(idx, -1);
            }
            // compute new depth
            long long new_val = val;
            long long new_depth = 0;
            while (new_val != 1) {
                new_val = __builtin_popcountll(new_val);
                new_depth++;
            }
            nums[idx] = val;
            depths[idx] = new_depth;
            if (new_depth <= 5) {
                bits[new_depth].update(idx, 1);
            }
        }
    }
    return answer;
}

